VALUES
  ('social-worker-moex-06970', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會服務組織的方案規劃人員正在進行一方案的預算系統設計，希望藉由此預算系統呈現該方案的輸出 相對於輸入比率，以預估執行該方案的單位成本，請問該組織方案規劃人員最適合採用何種預算系統？', '["單項預算系統", "功能預算系統", "平衡計分預算系統", "零基預算系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06971', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在各種方案評估中，何種評估最適合用來檢視一個服務方案是否能夠滿足規劃過程中所認知的社區需求？', '["成本效率評估", "成果評估", "影響力評估", "生產力評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06972', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '近年來社會服務組織越來越重視行銷策略的規劃執行，經常為商業部門所運用，由Jerome McCarthy所提 出的「4P」行銷組合概念，也逐漸被廣泛運用於社會服務領域，所謂的「4P」行銷組合概念即是：', '["product, promotion, price, place", "product, promotion, price, policy", "product, promotion, price, people", "product, promotion, price, proposal"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06973', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織財務管理專家Regina Herzlinger提出的DADS策略，主張與組織有關的資訊應做到四項內涵， 才能贏得社會信任，請問這四項是：', '["揭露、分析、散布、制裁（disclosure, analysis, dissemination, sanction）", "決定、分析、揭露、制裁（decision, analysis, disclosure, sanction）", "決定、分析、定義、制裁（decision, analysis, definition, sanction）", "定義、分析、散布、制裁（definition, analysis, dissemination, sanction）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06974', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某兒童福利機構委託陳教授協助建立員工的績效管理系統，陳教授首先請該機構的高階管理核心人員規劃 出組織的整體目標，並邀請各個部門的單位主管與其部屬根據整體目標，共同設定出部門目標與個人目 標，據此規劃行動方案，以定期檢視目標達成進度，請問此方法最符合下列何種員工的績效管理系統？', '["全面品質管理", "目標管理", "相對比較管理", "平衡計分卡管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06975', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '督導工作是社工領域管理者相當重要的任務，當受督導者在專業上的發展層次類似，且有類似需求時， 最適合運用的督導方式是：', '["機動式督導", "跨科際督導", "個案諮詢", "團隊督導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06976', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當員工績效考評者對某一個人的整體印象是基於某個單一特性，而推論其整體表現，此稱為何種效應？', '["月暈效應", "刻板印象效應", "尖角效應", "初始效應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "861375f44ec1", "answer_pdf_sha1": "a6b708cb0119", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
